    codeSolution: "using System;\n\n// Local class that conflicts with System namespace\nclass System\n{\n    public static void WriteMessage(string msg)\n    {\n        Console.WriteLine($\"Local System class says: {msg}\");\n    }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        // Local System class is used by default\n        System.WriteMessage(\"Hello from local\");\n        \n        // Global:: forces using the root System namespace\n        global::System.Console.WriteLine(\"Hello from global System.Console\");\n        \n        // Using alias for global system\n        using SysConsole = global::System.Console;\n        SysConsole.WriteLine(\"Using alias with global::\");\n        \n        // Another example: accessing System.Collections.Generic\n        var list = new global::System.Collections.Generic.List<int>();\n        list.Add(10);\n        SysConsole.WriteLine($\"List count: {list.Count}\");\n    }\n}",
