    codeSolution: "using System;\n\nenum Month\n{\n    January = 1,\n    February = 2,\n    March = 3,\n    April = 4,\n    May = 5,\n    June = 6,\n    July = 7,\n    August = 8,\n    September = 9,\n    October = 10,\n    November = 11,\n    December = 12\n}\n\nclass Program\n{\n    static void Main()\n    {\n        int monthValue = 3;\n        string monthName = Enum.GetName(typeof(Month), monthValue);\n        Console.WriteLine($\"Month {monthValue}: {monthName}\");\n        \n        // Using ToString() on enum\n        Month march = Month.March;\n        Console.WriteLine($\"ToString(): {march.ToString()}\");\n        \n        // Get all names\n        Console.WriteLine(\"\\nAll month names:\");\n        foreach (string name in Enum.GetNames(typeof(Month)))\n        {\n            Console.WriteLine($\"  {name}\");\n        }\n    }\n}",
