    question: "Create a command-line calculator with expression evaluation.",
    mathSolution: "Interactive calculator with input parsing.",
    codeSolution: "using System;\nusing System.Data;\n\nclass Program\n{\n    static void Main()\n    {\n        Console.WriteLine(\"Simple Calculator - Enter expressions (e.g., '5 + 3')\");\n        Console.WriteLine(\"Type 'exit' to quit\\n\");\n        \n        while (true)\n        {\n            Console.Write(\"Calc: \");\n            string input = Console.ReadLine();\n            \n            if (input?.ToLower() == \"exit\")\n                break;\n                \n            try\n            {\n                string[] parts = input.Split(' ');\n                if (parts.Length == 3)\n                {\n                    double a = double.Parse(parts[0]);\n                    string op = parts[1];\n                    double b = double.Parse(parts[2]);\n                    double result = 0;\n                    \n                    switch (op)\n                    {\n                        case \"+\": result = a + b; break;\n                        case \"-\": result = a - b; break;\n                        case \"*\": result = a * b; break;\n                        case \"/\": result = a / b; break;\n                        default: Console.WriteLine(\"Invalid operator\"); continue;\n                    }\n                    \n                    Console.WriteLine($\" = {result}\");\n                }\n                else\n                {\n                    Console.WriteLine(\"Format: number operator number\");\n                }\n            }\n            catch\n            {\n                Console.WriteLine(\"Invalid expression\");\n            }\n        }\n    }\n}",
    hint: "Use Split() to parse expressions and switch for operations.",
